bool ProductImages::validateJsonForCreation(const Json::Value &pJson, std::string &err)
{
    if(pJson.isMember("id"))
    {
        if(!validJsonOfField(0, "id", pJson["id"], err, true))
            return false;
    }
    if(pJson.isMember("product_id"))
    {
        if(!validJsonOfField(1, "product_id", pJson["product_id"], err, true))
            return false;
    }
    else
    {
        err="The product_id column cannot be null";
        return false;
    }
    if(pJson.isMember("url"))
    {
        if(!validJsonOfField(2, "url", pJson["url"], err, true))
            return false;
    }
    else
    {
        err="The url column cannot be null";
        return false;
    }
    if(pJson.isMember("is_cover"))
    {
        if(!validJsonOfField(3, "is_cover", pJson["is_cover"], err, true))
            return false;
    }
    if(pJson.isMember("sort_order"))
    {
        if(!validJsonOfField(4, "sort_order", pJson["sort_order"], err, true))
            return false;
    }
    if(pJson.isMember("uploaded_by"))
    {
        if(!validJsonOfField(5, "uploaded_by", pJson["uploaded_by"], err, true))
            return false;
    }
    if(pJson.isMember("created_at"))
    {
        if(!validJsonOfField(6, "created_at", pJson["created_at"], err, true))
            return false;
    }
    return true;
}
